import{_ as n,c as i,o as t,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Installation: Schnellstart in 5 Minuten | opencode-dcp","description":"Lernen Sie die Installation des DCP-Plugins kennen. Richten Sie alles in 5 Minuten ein, reduzieren Sie Token-Verbrauch bei langen Konversationen durch automatische Bereinigung und verbessern Sie die KI-Antwortqualität.","frontmatter":{"title":"Installation: Schnellstart in 5 Minuten | opencode-dcp","sidebarTitle":"In 5 Minuten starten","subtitle":"Installation: Schnellstart in 5 Minuten","description":"Lernen Sie die Installation des DCP-Plugins kennen. Richten Sie alles in 5 Minuten ein, reduzieren Sie Token-Verbrauch bei langen Konversationen durch automatische Bereinigung und verbessern Sie die KI-Antwortqualität.","tags":["Installation","Schnellstart","DCP"],"prerequisite":["OpenCode ist installiert"],"order":1},"headers":[],"relativePath":"de/Opencode-DCP/opencode-dynamic-context-pruning/start/getting-started/index.md","filePath":"de/Opencode-DCP/opencode-dynamic-context-pruning/start/getting-started/index.md"}'),s={name:"de/Opencode-DCP/opencode-dynamic-context-pruning/start/getting-started/index.md"};function o(r,e,l,d,c,u){return t(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="installation-und-schnellstart" tabindex="-1">Installation und Schnellstart <a class="header-anchor" href="#installation-und-schnellstart" aria-label="Permalink to &quot;Installation und Schnellstart&quot;">​</a></h1><h2 id="was-sie-nach-diesem-tutorial-konnen" tabindex="-1">Was Sie nach diesem Tutorial können <a class="header-anchor" href="#was-sie-nach-diesem-tutorial-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Tutorial können&quot;">​</a></h2><ul><li>✅ DCP-Plugin in 5 Minuten installieren</li><li>✅ Plugin konfigurieren und erfolgreiche Installation verifizieren</li><li>✅ Die erste automatische Bereinigung in Aktion sehen</li></ul><h2 id="ihre-aktuelle-situation" tabindex="-1">Ihre aktuelle Situation <a class="header-anchor" href="#ihre-aktuelle-situation" aria-label="Permalink to &quot;Ihre aktuelle Situation&quot;">​</a></h2><p>Bei längerer Nutzung von OpenCode werden die Konversationen immer länger:</p><ul><li>Die KI liest dieselbe Datei mehrmals</li><li>Fehlermeldungen von Tool-Aufrufen füllen den Kontext</li><li>Jede Konversation verbraucht eine große Menge an Token</li><li><strong>Je länger die Konversation, desto langsamer die KI-Antworten</strong></li></ul><p>Sie möchten redundante Inhalte in der Konversation automatisch bereinigen, ohne manuell eingreifen zu müssen.</p><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p><strong>DCP (Dynamic Context Pruning)</strong> ist ein OpenCode-Plugin, das redundante Tool-Aufrufe aus dem Konversationsverlauf automatisch entfernt und so den Token-Verbrauch reduziert.</p><p>So funktioniert es:</p><ol><li><strong>Automatische Erkennung</strong>: Vor jedem Nachrichtenversand wird der Konversationsverlauf automatisch analysiert</li><li><strong>Intelligente Bereinigung</strong>: Entfernt wiederholte Tool-Aufrufe, veraltete Fehler und überschriebene Schreibvorgänge</li><li><strong>KI-gesteuert</strong>: Die KI kann aktiv die Tools <code>discard</code> und <code>extract</code> aufrufen, um den Kontext zu optimieren</li><li><strong>Transparent und kontrollierbar</strong>: Über den Befehl <code>/dcp</code> können Bereinigungsstatistiken eingesehen und manuelle Bereinigungen ausgelöst werden</li></ol><div class="tip custom-block"><p class="custom-block-title">Kernvorteile</p><ul><li><strong>Kostenlos</strong>: Automatische Strategien erfordern keine LLM-Aufrufe</li><li><strong>Keine Konfiguration</strong>: Sofort einsatzbereit, die Standardkonfiguration ist bereits optimiert</li><li><strong>Risikofrei</strong>: Es wird nur der an die LLM gesendete Kontext geändert, der Konversationsverlauf bleibt unberührt</li></ul></div><h2 id="🎒-vorbereitung" tabindex="-1">🎒 Vorbereitung <a class="header-anchor" href="#🎒-vorbereitung" aria-label="Permalink to &quot;🎒 Vorbereitung&quot;">​</a></h2><p>Bevor Sie mit der Installation beginnen, prüfen Sie bitte:</p><ul><li>[ ] <strong>OpenCode</strong> ist installiert (unterstützt Plugin-Funktion)</li><li>[ ] Sie wissen, wie Sie die <strong>OpenCode-Konfigurationsdatei</strong> bearbeiten</li><li>[ ] Sie verstehen die Grundlagen der <strong>JSONC-Syntax</strong> (JSON mit Kommentaren)</li></ul><div class="warning custom-block"><p class="custom-block-title">Wichtiger Hinweis</p><p>DCP ändert den an die LLM gesendeten Kontext, beeinflusst jedoch nicht Ihren Konversationsverlauf. Sie können das Plugin jederzeit in der Konfiguration deaktivieren.</p></div><h2 id="schritt-fur-schritt" tabindex="-1">Schritt für Schritt <a class="header-anchor" href="#schritt-fur-schritt" aria-label="Permalink to &quot;Schritt für Schritt&quot;">​</a></h2><h3 id="schritt-1-opencode-konfigurationsdatei-bearbeiten" tabindex="-1">Schritt 1: OpenCode-Konfigurationsdatei bearbeiten <a class="header-anchor" href="#schritt-1-opencode-konfigurationsdatei-bearbeiten" aria-label="Permalink to &quot;Schritt 1: OpenCode-Konfigurationsdatei bearbeiten&quot;">​</a></h3><p><strong>Warum</strong> Sie müssen das DCP-Plugin in der OpenCode-Konfiguration deklarieren, damit es beim Start automatisch geladen wird.</p><p>Öffnen Sie Ihre OpenCode-Konfigurationsdatei <code>opencode.jsonc</code> und fügen Sie DCP im Feld <code>plugin</code> hinzu:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// opencode.jsonc</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@tarquinen/opencode-dcp@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>: Die Konfigurationsdatei enthält möglicherweise bereits andere Plugins (falls vorhanden). Fügen Sie DCP einfach am Ende des Arrays hinzu.</p><div class="info custom-block"><p class="custom-block-title">Hinweis</p><p>Mit dem Tag <code>@latest</code> prüft OpenCode bei jedem Start automatisch auf die neueste Version.</p></div><h3 id="schritt-2-opencode-neu-starten" tabindex="-1">Schritt 2: OpenCode neu starten <a class="header-anchor" href="#schritt-2-opencode-neu-starten" aria-label="Permalink to &quot;Schritt 2: OpenCode neu starten&quot;">​</a></h3><p><strong>Warum</strong> Nach Änderungen an der Plugin-Konfiguration ist ein Neustart erforderlich, damit diese wirksam werden.</p><p>Schließen Sie OpenCode vollständig und starten Sie es neu.</p><p><strong>Sie sollten sehen</strong>: OpenCode startet normal ohne Fehlermeldungen.</p><h3 id="schritt-3-plugin-installation-verifizieren" tabindex="-1">Schritt 3: Plugin-Installation verifizieren <a class="header-anchor" href="#schritt-3-plugin-installation-verifizieren" aria-label="Permalink to &quot;Schritt 3: Plugin-Installation verifizieren&quot;">​</a></h3><p><strong>Warum</strong> Bestätigen Sie, dass das DCP-Plugin korrekt geladen wurde, und sehen Sie sich die Standardkonfiguration an.</p><p>Geben Sie in der OpenCode-Konversation ein:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/dcp</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>: Die DCP-Befehlshilfe, die anzeigt, dass das Plugin erfolgreich installiert wurde.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Commands                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /dcp context      Show token usage breakdown for current session</span></span>
<span class="line"><span>  /dcp stats        Show DCP pruning statistics</span></span>
<span class="line"><span>  /dcp sweep [n]    Prune tools since last user message, or last n tools</span></span></code></pre></div><h3 id="schritt-4-standardkonfiguration-anzeigen" tabindex="-1">Schritt 4: Standardkonfiguration anzeigen <a class="header-anchor" href="#schritt-4-standardkonfiguration-anzeigen" aria-label="Permalink to &quot;Schritt 4: Standardkonfiguration anzeigen&quot;">​</a></h3><p><strong>Warum</strong> Verstehen Sie die DCP-Standardkonfiguration und prüfen Sie, ob das Plugin wie erwartet funktioniert.</p><p>DCP erstellt beim ersten Start automatisch eine Konfigurationsdatei:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Globale Konfigurationsdatei anzeigen</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode/dcp.jsonc</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>: Die Konfigurationsdatei wurde erstellt und enthält initial nur das Feld <code>$schema</code>:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://raw.githubusercontent.com/Opencode-DCP/opencode-dynamic-context-pruning/master/dcp.schema.json&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Die Konfigurationsdatei enthält initial nur das <code>$schema</code>-Feld. Alle anderen Konfigurationselemente verwenden die Standardwerte aus dem Code und können ohne manuelle Konfiguration genutzt werden.</p><div class="tip custom-block"><p class="custom-block-title">Erklärung der Standardkonfiguration</p><p>Die Standardwerte von DCP im Code sind wie folgt (müssen nicht in die Konfigurationsdatei geschrieben werden):</p><ul><li><strong>deduplication</strong>: Automatische Deduplizierung, entfernt wiederholte Tool-Aufrufe</li><li><strong>purgeErrors</strong>: Automatische Bereinigung von Fehler-Tool-Eingaben vor 4 Runden</li><li><strong>discard/extract</strong>: Von der KI aufrufbare Bereinigungstools</li><li><strong>pruneNotification</strong>: Detaillierte Bereinigungsbenachrichtigungen anzeigen</li></ul><p>Wenn Sie eine benutzerdefinierte Konfiguration benötigen, können Sie diese Felder manuell hinzufügen. Detaillierte Konfigurationsanweisungen finden Sie unter <a href="./../configuration/">Konfiguration im Detail</a>.</p></div><h3 id="schritt-5-automatische-bereinigung-erleben" tabindex="-1">Schritt 5: Automatische Bereinigung erleben <a class="header-anchor" href="#schritt-5-automatische-bereinigung-erleben" aria-label="Permalink to &quot;Schritt 5: Automatische Bereinigung erleben&quot;">​</a></h3><p><strong>Warum</strong> DCP in der Praxis nutzen und die automatische Bereinigung in Aktion sehen.</p><p>Führen Sie in OpenCode eine Konversation, bei der die KI dieselbe Datei mehrmals liest oder einige fehlgeschlagene Tool-Aufrufe ausführt.</p><p><strong>Sie sollten sehen</strong>:</p><ol><li>Bei jedem Nachrichtenversand analysiert DCP automatisch den Konversationsverlauf</li><li>Bei wiederholten Tool-Aufrufen bereinigt DCP automatisch</li><li>Nach der KI-Antwort sehen Sie möglicherweise eine Bereinigungsbenachrichtigung (abhängig von der <code>pruneNotification</code>-Konfiguration)</li></ol><p>Beispiel einer Bereinigungsbenachrichtigung:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>▣ DCP | ~12.5K tokens saved total</span></span>
<span class="line"><span></span></span>
<span class="line"><span>▣ Pruning (~12.5K tokens)</span></span>
<span class="line"><span>→ read: src/config.ts</span></span>
<span class="line"><span>→ write: package.json</span></span></code></pre></div><p>Geben Sie <code>/dcp context</code> ein, um die aktuelle Token-Nutzung der Sitzung anzuzeigen:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Session Context Breakdown:</span></span>
<span class="line"><span>──────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System         15.2% │████████████████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│  25.1K tokens</span></span>
<span class="line"><span>User            5.1% │████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│   8.4K tokens</span></span>
<span class="line"><span>Assistant       35.8% │██████████████████████████████████████▒▒▒▒▒▒▒│  59.2K tokens</span></span>
<span class="line"><span>Tools (45)      43.9% │████████████████████████████████████████████████│  72.6K tokens</span></span>
<span class="line"><span></span></span>
<span class="line"><span>──────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Summary:</span></span>
<span class="line"><span>  Pruned:          12 tools (~15.2K tokens)</span></span>
<span class="line"><span>  Current context: ~165.3K tokens</span></span>
<span class="line"><span>  Without DCP:     ~180.5K tokens</span></span></code></pre></div><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>Nach Abschluss der obigen Schritte sollten Sie:</p><ul><li>[ ] DCP-Plugin in <code>opencode.jsonc</code> hinzugefügt haben</li><li>[ ] OpenCode nach dem Neustart normal ausführen können</li><li>[ ] <code>/dcp</code>-Befehl zeigt Hilfeinformationen an</li><li>[ ] Konfigurationsdatei <code>~/.config/opencode/dcp.jsonc</code> wurde erstellt</li><li>[ ] Bereinigungsbenachrichtigungen in der Konversation sehen oder Bereinigungsstatistiken über <code>/dcp context</code> einsehen können</li></ul><p><strong>Falls ein Schritt fehlschlägt</strong>:</p><ul><li>Prüfen Sie, ob die Syntax von <code>opencode.jsonc</code> korrekt ist (JSONC-Format)</li><li>Sehen Sie sich die OpenCode-Logs auf Plugin-Ladefehler an</li><li>Stellen Sie sicher, dass die OpenCode-Version Plugin-Funktionen unterstützt</li></ul><h2 id="fehlerbehebung" tabindex="-1">Fehlerbehebung <a class="header-anchor" href="#fehlerbehebung" aria-label="Permalink to &quot;Fehlerbehebung&quot;">​</a></h2><h3 id="problem-1-plugin-nicht-aktiv" tabindex="-1">Problem 1: Plugin nicht aktiv <a class="header-anchor" href="#problem-1-plugin-nicht-aktiv" aria-label="Permalink to &quot;Problem 1: Plugin nicht aktiv&quot;">​</a></h3><p><strong>Symptom</strong>: Konfiguration hinzugefügt, aber keine Bereinigungseffekte sichtbar</p><p><strong>Ursache</strong>: OpenCode wurde nicht neu gestartet oder falscher Konfigurationsdateipfad</p><p><strong>Lösung</strong>:</p><ol><li>OpenCode vollständig schließen und neu starten</li><li>Prüfen Sie, ob der Pfad von <code>opencode.jsonc</code> korrekt ist</li><li>Logs anzeigen: Log-Dateien im Verzeichnis <code>~/.config/opencode/logs/dcp/daily/</code></li></ol><h3 id="problem-2-konfigurationsdatei-nicht-erstellt" tabindex="-1">Problem 2: Konfigurationsdatei nicht erstellt <a class="header-anchor" href="#problem-2-konfigurationsdatei-nicht-erstellt" aria-label="Permalink to &quot;Problem 2: Konfigurationsdatei nicht erstellt&quot;">​</a></h3><p><strong>Symptom</strong>: <code>~/.config/opencode/dcp.jsonc</code> existiert nicht</p><p><strong>Ursache</strong>: OpenCode hat das DCP-Plugin nicht aufgerufen oder Berechtigungsprobleme im Konfigurationsverzeichnis</p><p><strong>Lösung</strong>:</p><ol><li>Stellen Sie sicher, dass OpenCode neu gestartet wurde</li><li>Konfigurationsverzeichnis manuell erstellen: <code>mkdir -p ~/.config/opencode</code></li><li>Prüfen Sie in <code>opencode.jsonc</code>, ob der Plugin-Name korrekt ist: <code>@tarquinen/opencode-dcp@latest</code></li></ol><h3 id="problem-3-bereinigungsbenachrichtigungen-werden-nicht-angezeigt" tabindex="-1">Problem 3: Bereinigungsbenachrichtigungen werden nicht angezeigt <a class="header-anchor" href="#problem-3-bereinigungsbenachrichtigungen-werden-nicht-angezeigt" aria-label="Permalink to &quot;Problem 3: Bereinigungsbenachrichtigungen werden nicht angezeigt&quot;">​</a></h3><p><strong>Symptom</strong>: Keine Bereinigungsbenachrichtigungen gesehen, aber <code>/dcp stats</code> zeigt Bereinigungen an</p><p><strong>Ursache</strong>: <code>pruneNotification</code> ist auf <code>&quot;off&quot;</code> oder <code>&quot;minimal&quot;</code> konfiguriert</p><p><strong>Lösung</strong>: Konfigurationsdatei bearbeiten:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pruneNotification&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;detailed&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // oder &quot;minimal&quot;</span></span></code></pre></div><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p>Die Installation des DCP-Plugins ist sehr einfach:</p><ol><li>Plugin in <code>opencode.jsonc</code> hinzufügen</li><li>OpenCode neu starten</li><li>Installation mit <code>/dcp</code>-Befehl verifizieren</li><li>Standardkonfiguration kann sofort genutzt werden, keine weiteren Anpassungen nötig</li></ol><p><strong>Standardmäßig aktivierte DCP-Funktionen</strong>:</p><ul><li>✅ Automatische Deduplizierungsstrategie (entfernt wiederholte Tool-Aufrufe)</li><li>✅ Fehlerbereinigungsstrategie (bereinigt veraltete Fehlereingaben)</li><li>✅ KI-gesteuerte Tools (<code>discard</code> und <code>extract</code>)</li><li>✅ Detaillierte Bereinigungsbenachrichtigungen</li></ul><p><strong>Nächster Schritt</strong>: Erfahren Sie, wie Sie die Konfiguration anpassen und Bereinigungsstrategien für verschiedene Szenarien anpassen können.</p><hr><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../configuration/">Konfiguration im Detail</a></strong></p><p>Sie werden lernen:</p><ul><li>Mehrstufiges Konfigurationssystem (global, Umgebungsvariablen, projektbezogen)</li><li>Funktion und empfohlene Einstellungen aller Konfigurationselemente</li><li>Rundenschutz, geschützte Tools, geschützte Dateimuster</li><li>Wie verschiedene Bereinigungsstrategien aktiviert/deaktiviert werden</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisiert: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>Plugin-Einstieg</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/index.ts" target="_blank" rel="noreferrer"><code>index.ts</code></a></td><td>12-102</td></tr><tr><td>Konfigurationsverwaltung</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/config.ts" target="_blank" rel="noreferrer"><code>lib/config.ts</code></a></td><td>669-794</td></tr><tr><td>Befehlsverarbeitung</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/help.ts" target="_blank" rel="noreferrer"><code>lib/commands/help.ts</code></a></td><td>1-40</td></tr><tr><td>Token-Berechnung</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>68-174</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>MAX_TOOL_CACHE_SIZE = 1000</code>: Maximale Anzahl von Einträgen im Tool-Cache</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>Plugin()</code>: Plugin-Registrierung und Hook-Einrichtung</li><li><code>getConfig()</code>: Laden und Zusammenführen mehrstufiger Konfigurationen</li><li><code>handleContextCommand()</code>: Analyse der aktuellen Sitzungs-Token-Nutzung</li></ul></details>`,83)])])}const p=n(s,[["render",o]]);export{g as __pageData,p as default};
